# Category: ssrf

local cjson = require "cjson"
local http = require("resty.http") -- 引入依赖库
function log(message)
  ngx.log(ngx.NOTICE, message .. "\n")
end
if not ngx.var then
    log(ngx.ERR, "no input arg")
    return 404
end 

target_url = ngx.var.arg_url or 'https://github.com' -- 如果没有传入，默认返回github主页

local res, err = http:request_uri(target_url)
if not res then
   log(ngx.ERR,"http:request_uri() failed with error:", err) 
   return 403
end

if res.status ~= 200 then
  -- ngx.status = ngx.HTTP_SERVICE_UNAVAILABLE
   ngx.status = 502
--  ngx.exit(ngx.HTTP_BAD_GATEWAY)
   log(ngx.ERR,"http:request_uri() return ", res.status, " instead of 200.")  
   return 418 -- I'm a teapot
end
 
if res then
   content = cjson.decode(res.body)
   ngx.say(content['message'] or 'Hello world')
   
   log(ngx.ERR,"HTTP status: ",res.status,'\n','HTTP body:',res.body,'\n','HTTP headers:',cjson.encode(res.headers))
end

ngx.exit(204)